@implements IAsyncDisposable
@inject IJSRuntime JS

<div @ref="_element">
    @ChildContent
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public int TimeoutSeconds { get; set; } = 300;
    [Parameter] public EventCallback OnIdle { get; set; }
    [Parameter] public EventCallback OnActive { get; set; }

    private ElementReference _element;
    private IJSObjectReference? _jsModule;
    private DotNetObjectReference<UserActivityTracker>? _dotNetRef;
    private System.Timers.Timer? _timer;
    private bool _isIdle;
    private bool _disposed;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender) return;

        _dotNetRef = DotNetObjectReference.Create(this);
        _jsModule = await JS.InvokeAsync<IJSObjectReference>(
            "import", "./_content/sv-f642d770f3be4341acf778a388d3acf7/Components/UserActivityTracker.razor.js");
        await _jsModule.InvokeVoidAsync("init", _element, _dotNetRef);

        _timer = new System.Timers.Timer(TimeoutSeconds * 1000);
        _timer.AutoReset = false;
        _timer.Elapsed += OnTimerElapsed;
        _timer.Start();
    }

    [JSInvokable]
    public async Task NotifyActivity()
    {
        if (_disposed) return;

        _timer?.Stop();
        _timer?.Start();

        if (_isIdle)
        {
            _isIdle = false;
            await InvokeAsync(OnActive.InvokeAsync);
        }
    }

    private async void OnTimerElapsed(object? sender, System.Timers.ElapsedEventArgs e)
    {
        if (_disposed) return;

        _isIdle = true;
        await InvokeAsync(OnIdle.InvokeAsync);
    }

    public async ValueTask DisposeAsync()
    {
        if (_disposed) return;
        _disposed = true;

        if (_timer is not null)
        {
            _timer.Elapsed -= OnTimerElapsed;
            _timer.Stop();
            _timer.Dispose();
            _timer = null;
        }

        if (_jsModule is not null)
        {
            try
            {
                await _jsModule.InvokeVoidAsync("dispose");
                await _jsModule.DisposeAsync();
            }
            catch (JSDisconnectedException) { }
        }

        _dotNetRef?.Dispose();
    }
}

let element = null;
let dotNetRef = null;
const events = ['mousemove', 'keydown', 'click', 'scroll'];

function onActivity() {
    dotNetRef?.invokeMethodAsync('NotifyActivity');
}

export function init(el, ref) {
    element = el;
    dotNetRef = ref;
    events.forEach(e => element.addEventListener(e, onActivity, { passive: true }));
}

export function dispose() {
    if (element) {
        events.forEach(e => element.removeEventListener(e, onActivity));
    }
    element = null;
    dotNetRef = null;
}

