@@ -1,0 +1,22 @@
+let element = null;
+let dotNetRef = null;
+const events = ['mousemove', 'keydown', 'click', 'scroll'];
+
+function onActivity() {
+    dotNetRef?.invokeMethodAsync('NotifyActivity');
+}
+
+export function init(el, ref) {
+    element = el;
+    dotNetRef = ref;
+    events.forEach(e => element.addEventListener(e, onActivity, { passive: true }));
+}
+
+export function dispose() {
+    if (element) {
+        events.forEach(e => element.removeEventListener(e, onActivity));
+    }
+    element = null;
+    dotNetRef = null;
+}
+
